const INSTAGRAM_URL_REGEX = /^https?:\/\/(www\.)?instagram\.com\/(p|reel|tv)\/[A-Za-z0-9_-]+\/?(\?[^\s]*)?$/i;
const isInstagramUrl = url => INSTAGRAM_URL_REGEX.test((url||"").trim());

