// Real IBAN validation: basic format + the mod-97 checksum used by all IBANs,
// so no external library is needed.
const isValidIban = raw => {
  const iban = (raw||"").replace(/\s+/g,"").toUpperCase();
  if (!/^[A-Z]{2}\d{2}[A-Z0-9]{11,30}$/.test(iban)) return false;
  const rearranged = iban.slice(4) + iban.slice(0,4);
  const numeric = rearranged.replace(/[A-Z]/g, ch => (ch.charCodeAt(0)-55).toString());
  let remainder = 0;
  for (let i=0;i<numeric.length;i++) remainder = (remainder*10 + Number(numeric[i])) % 97;
  return remainder === 1;
};

// ─── AUTH (real Firebase Auth) ──────────────────────────────────────────────
// Google sign-in uses signInWithPopup; email/password uses
// signInWithEmailAndPassword (sign-in) and createUserWithEmailAndPassword
// (new applications, in SignupForm below). Neither handler sets currentUser
// directly — App's onAuthStateChanged listener is the single place that
// happens, since it also needs to load/create each user's Firestore profile
// doc and check pending-application status before granting access.

// Maps Firebase Auth error codes to short, friendly copy. Falls back to a
// generic message for anything not explicitly listed — Firebase's raw
// e.message strings are written for developers, not end users.
function authErrorMessage(e) {
  const code = e?.code || "";
  const map = {
    "auth/wrong-password": "Incorrect email or password.",
    "auth/user-not-found": "No account found with that email.",
    "auth/invalid-credential": "Incorrect email or password.",
    "auth/invalid-email": "Enter a valid email address.",
    "auth/email-already-in-use": "An account with that email already exists.",
    "auth/weak-password": "Password should be at least 6 characters.",
    "auth/popup-closed-by-user": "Sign-in was cancelled.",
    "auth/cancelled-popup-request": "Sign-in was cancelled.",
    "auth/popup-blocked": "Your browser blocked the sign-in popup — allow popups for this site and try again.",
    "auth/too-many-requests": "Too many attempts — please wait a moment and try again.",
    "auth/network-request-failed": "Network error — check your connection and try again.",
    "auth/user-disabled": "This account has been disabled.",
  };
  return map[code] || "Something went wrong — please try again.";
}

