function SignupForm({ onSubmitApplication, onBackToSignIn }) {
  const [form, setForm] = useState({ name:"", email:"", password:"", instagramHandle:"", contentType:"", publicConfirmed:false });
  const [submitted, setSubmitted] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const handleValid = isValidInstagramHandle(form.instagramHandle);
  const canSubmit = form.name && form.email && form.password && handleValid && form.contentType && form.publicConfirmed;

  // Creates a real Firebase Auth account up front (so the password they just
  // chose works later once approved), writes their application as a
  // status:"pending" profile doc, then signs them back out immediately —
  // createUserWithEmailAndPassword auto-signs-in the new account, but a
  // pending applicant shouldn't slip into the app before an admin approves
  // them. App.jsx's onAuthStateChanged listener also checks for
  // status:"pending" as a second line of defense if this signOut is ever
  // skipped (e.g. due to a network blip).
  const submit = async () => {
    if (!canSubmit || submitting) return;
    setError("");
    setSubmitting(true);
    const cleanHandle = form.instagramHandle.replace(/^@/,"");
    try {
      const cred = await createUserWithEmailAndPassword(auth, form.email, form.password);
      await setDoc(doc(db, "users", cred.user.uid), {
        name: form.name,
        email: form.email,
        handle: `@${cleanHandle}`,
        username: cleanHandle,
        bio: "",
        plan: "Free",
        provider: "email",
        status: "pending",
        role: "member",
        circle: "A",
        contentType: form.contentType,
        points: 0,
        supportCount: 0,
        verified: false,
        verifiedAtSupportCount: 0,
        verifiedAt: null,
        joined: new Date().toISOString().slice(0,10),
        createdAt: serverTimestamp(),
      });
      await signOut(auth);
      onSubmitApplication && onSubmitApplication({ name:form.name, email:form.email, instagramHandle:cleanHandle, contentType:form.contentType });
      setSubmitted(true);
    } catch (e) {
      setError(authErrorMessage(e));
    } finally {
      setSubmitting(false);
    }
  };

  if (submitted) {
    const cleanHandle = form.instagramHandle.replace(/^@/,"");
    return (
      <div style={{textAlign:"center", padding:"50px 16px"}}>
        <div style={{marginBottom:20, display:"flex", justifyContent:"center"}}>
          <div style={{width:72, height:72, borderRadius:"50%", background:"rgba(78,204,163,0.12)", border:"2px solid rgba(78,204,163,0.3)", display:"flex", alignItems:"center", justifyContent:"center"}}>
            <Icon name="check" size={32} color={C.green}/>
          </div>
        </div>
        <div style={{fontSize:22, fontWeight:700, letterSpacing:-0.5, marginBottom:8}}>Application submitted</div>
        <div style={{fontSize:13, color:C.textMuted, lineHeight:1.6, marginBottom:24}}>
          Our team will confirm @{cleanHandle} is public and review your application. We'll email {form.email} once you're approved.
        </div>
        <button className="btn btn-ghost" onClick={onBackToSignIn}>Back to sign in</button>
      </div>
    );
  }

  return (
    <div style={{padding:"26px 24px 40px"}}>
      <div style={{textAlign:"center", marginBottom:24}}>
        <img src={LOGO_ICON_SRC} alt="CreatorCircle" style={{width:56, height:56, margin:"0 auto 14px", display:"block"}}/>
        <div style={{fontSize:22, fontWeight:700, letterSpacing:-0.5}}>Apply to join</div>
        <div style={{fontSize:13, color:C.textMuted, marginTop:6, lineHeight:1.5}}>Tell us about your content — every application is reviewed before approval</div>
      </div>

      <div className="field">
        <label className="field-lbl">Full name</label>
        <input className="field-inp" placeholder="Your name" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))}/>
      </div>
      <div className="field">
        <label className="field-lbl">Email</label>
        <input className="field-inp" type="email" placeholder="you@example.com" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))}/>
      </div>
      <div className="field">
        <label className="field-lbl">Password</label>
        <input className="field-inp" type="password" placeholder="••••••••" value={form.password} onChange={e=>setForm(f=>({...f,password:e.target.value}))}/>
      </div>

      <div className="field">
        <label className="field-lbl">Your platform</label>
        <div style={{display:"flex", gap:6, flexWrap:"wrap", marginBottom:10}}>
          {PLATFORMS.map(p=>(
            <div key={p.key} className={`chip ${p.key==="instagram"?"chip-accent":"chip-ghost"}`} style={{opacity:p.enabled?1:0.55, cursor:"default"}}>
              {p.label}{!p.enabled && <span style={{marginLeft:5,fontSize:9,color:C.amber}}>Soon</span>}
            </div>
          ))}
        </div>
        <input className="field-inp" placeholder="Instagram username (without @)" value={form.instagramHandle} onChange={e=>setForm(f=>({...f,instagramHandle:e.target.value}))}/>
        {form.instagramHandle && !handleValid ? (
          <div style={{fontSize:11, color:C.coral, marginTop:6, lineHeight:1.4}}>Enter a valid Instagram username (letters, numbers, periods, underscores).</div>
        ) : (
          <div style={{fontSize:11, color:C.textDim, marginTop:6, lineHeight:1.4}}>Only Instagram is supported right now — other platforms are coming soon.</div>
        )}
      </div>

      <div className="field">
        <label className="field-lbl">Type of content</label>
        <div style={{display:"flex", gap:6, flexWrap:"wrap"}}>
          {CIRCLE_GROUPS.map(g=>(
            <div key={g} className={`chip ${form.contentType===g?"chip-accent":"chip-ghost"}`} style={{fontSize:10, padding:"4px 10px"}} onClick={()=>setForm(f=>({...f,contentType:g}))}>{g}</div>
          ))}
        </div>
      </div>

      <div className={`checkbox-row ${form.publicConfirmed?"checked":""}`} style={{marginBottom:18}} onClick={()=>setForm(f=>({...f,publicConfirmed:!f.publicConfirmed}))}>
        <div className={`checkbox ${form.publicConfirmed?"checked":""}`}>{form.publicConfirmed && <Icon name="check" size={13} color={C.bg}/>}</div>
        <span style={{fontSize:13, color:C.textMuted, lineHeight:1.5}}>My Instagram account is set to <b style={{color:C.text}}>Public</b> — private accounts can't be verified for engagement.</span>
      </div>

      {error && <div style={{fontSize:12, color:C.coral, marginBottom:14, lineHeight:1.5}}>{error}</div>}

      <button className="btn btn-primary" style={{marginBottom:16}} disabled={!canSubmit||submitting} onClick={submit}>{submitting ? "Submitting…" : "Submit application"}</button>
      <div style={{textAlign:"center", fontSize:12, color:C.textMuted}}>
        Already approved? <span style={{color:C.accent, fontWeight:700, cursor:"pointer"}} onClick={onBackToSignIn}>Sign in</span>
      </div>
    </div>
  );
}

